customer = frappe.get_doc("Customer", doc.name)


if customer.customer_primary_contact:
    contact = frappe.get_doc("Contact", customer.customer_primary_contact)
    # Check if the contact is already linked to this customer
    existing_link = frappe.get_all("Dynamic Link", filters={
        'link_doctype': 'Customer',
        'link_name': customer.name,
        'parent': contact.name  # Parent is the Contact document
    })

    if existing_link:
        # The contact is already linked to this customer
        frappe.msgprint(f"Contact '{contact.name}' is already linked to the customer '{customer.name}'.")
    else:
        # Link the contact to the customer
        contact.append('links', {
            'link_doctype': 'Customer',
            'link_name': customer.name
        })
        contact.save()
        frappe.msgprint(f"Contact '{contact.name}' has been linked to the customer '{customer.name}'.")
else:
    frappe.msgprint("No Primary Contact was given")

def format_wa_id(phone):
    """Standardize the phone number for comparison."""
    phone = phone.replace('+', '').replace(' ', '').replace('-', '')
    if phone.startswith('0'):
        return '27' + phone[1:]
    elif phone.startswith('27'):
        return phone
    return phone

def get_attachments(whatsapp_message):
    """Fetch attachments for a given WhatsApp Message."""
    attachments = frappe.get_all(
        "File",
        filters={"attached_to_doctype": "WhatsApp Message", "attached_to_name": whatsapp_message.name},
        fields=["file_url", "file_name", "file_type"]
    )
    return [
        {
            'url': frappe.utils.get_url(attachment['file_url']),
            'name': attachment['file_name'],
            'type': attachment['file_type']
        }
        for attachment in attachments
    ]

def generate_attachment_preview(attachments):
    """Generate HTML previews for attachments."""
    previews = []
    for attachment in attachments:
        attachment_type = attachment['type'].lower()
        if attachment_type == 'application/pdf':
            preview_html = f'''
            <div class="attachment-preview">
                <iframe src="{attachment["url"]}" type="application/pdf" width="100%" height="150px"></iframe>
                <p>{attachment["name"]}</p>
            </div>
            '''
        elif attachment_type in ['audio/ogg', 'oga', 'ogg']:
            preview_html = f'''
            <div class="attachment-preview">
                <audio controls>
                    <source src="{attachment["url"]}" type="audio/ogg">
                    Your browser does not support the audio element.
                </audio>
            </div>
            '''
        else:
            # Assume it's an image or other previewable type
            preview_html = f'''
            <div class="attachment-preview">
                <img src="{attachment["url"]}" alt="Attachment preview" onclick="showModal('{attachment["url"]}')"/>
                <p>{attachment["name"]}</p>
            </div>
            '''
        previews.append(preview_html)
    return ''.join(previews)

def build_timeline_item(message, attachments):
    """Construct a single timeline item."""
    msg_class = "message-received" if message.get("type") == "Incoming" else "message-sent"
    content = frappe.utils.escape_html(message.get('message', 'No message provided'))
    timestamp = frappe.utils.format_datetime(message['creation'])

    # Add status checkmarks for sent messages
    check_mark = ""
    if msg_class == "message-sent":
        status = message.get('status')
        check_mark_mapping = {
            "Sent": '<span class="check-mark sent">🗸</span>',
            "Delivered": '<span class="check-mark delivered">🗸🗸</span>',
            "Seen": '<span class="check-mark seen">✅</span>',
            "Failed": '<span class="check-mark failed">❌</span>',
            "Pending": '<span class="check-mark pending">⌛</span>',
        }
        check_mark = check_mark_mapping.get(status, '')

    # Combine message and attachments
    attachments_html = generate_attachment_preview(attachments)
    return f'''
    <div class="timeline-item">
        <div class="{msg_class}">
            <p>{content}</p>
            {attachments_html}
            <div class="message-timestamp">{timestamp} {check_mark}</div>
        </div>
    </div>
    '''

def get_issue_communications(issue_name):
    """Fetch communications for an issue and generate the timeline HTML."""
    issue = frappe.get_doc("Issue", issue_name)
    contact_name = issue.custom_contact_chat
    if not contact_name:
        return
    contact = frappe.get_doc("Contact", contact_name)
    phone = contact.mobile_no

    whatsapp_messages = frappe.get_all(
        "WhatsApp Message",
        filters={"reference_doctype": "Issue", "reference_name": issue_name},
        or_filters=[{"to": phone}, {"from": phone}],
        fields=["*"]
    )
    whatsapp_messages.sort(key=lambda x: x['creation'], reverse=True)

    timeline_items = [
        build_timeline_item(message, get_attachments(message))
        for message in whatsapp_messages
    ]

    timeline_html = '''
