        text-align: left;
        word-wrap: break-word;
    }

    .message-received {
        background-color: #f1f1f1;
        color: #333;
        padding: 10px 15px;
        border-radius: 10px 10px 10px 0;
        max-width: 50%;
        margin-right: auto;
        text-align: left;
        word-wrap: break-word;
    }

    .message-timestamp {
        font-size: 0.8em;
        color: #888;
        margin-top: 5px;
        text-align: right;
    }

    .check-mark {
        font-size: 1em;
        color: #777;
        margin-left: 5px;
    }
    .check-mark.sent { color: #6c757d; }
    .check-mark.delivered { color: #007bff; }
    .check-mark.seen { color: #0069d9; }
    .check-mark.failed { color: #ff4136; }
    .check-mark.pending { color: #ff9800; }

    .attachment-preview {
        display: inline-block;
        text-align: center;
        cursor: pointer;
        margin-top: 10px;
    }

    .attachment-preview img {
        width: 80px;
        height: 80px;
        object-fit: cover;
        border-radius: 4px;
        margin-bottom: 5px;
    }

    .attachment-modal {
        display: none;
        position: fixed;
        top: 0;
        left: 0;
        width: 100%;
        height: 100%;
        background-color: rgba(0, 0, 0, 0.7);
        justify-content: center;
        align-items: center;
    }

    .attachment-modal img {
        max-width: 90%;
        max-height: 90%;
        object-fit: contain;
    }

    .attachment-preview iframe {
        width: 300px;
        height: 200px;
        margin-top: 10px;
    }

    .attachment-preview audio {
        width: 300px;
        max-width: 100%;
        border-radius: 5px;
        margin-top: 5px;
    }

    .attachment-modal {
        display: flex;
        justify-content: center;
        align-items: center;
        position: fixed;
        top: 0;
        left: 0;
        width: 100%;
        height: 100%;
        background-color: transparent;
        z-index: 1000;
        padding: 0;
        overflow: hidden;
    }

    .attachment-modal {
        display: flex;
        justify-content: center;
        align-items: center;
        position: fixed;
        top: 0;
        left: 0;
        width: 100%;
        height: 100%;
        background-color: rgba(0, 0, 0, 0.5);
        z-index: 1000;
        padding: 0;
        overflow: hidden;
    }

    .attachment-modal .modal-content {
        display: flex;
        justify-content: center;
        align-items: center;
        box-sizing: border-box;
        padding: 20px;
        width: 60%;
        max-width: 600px;
        height: auto;
    }

    .attachment-modal img {
        width: 100%;
        height: auto;
        object-fit: contain;
    }

    </style>

    <div class="timeline">
    ''' + ''.join(timeline_items) + '''
    </div>

    <script>
        function showModal(url) {
            console.log("showModal triggered for URL: ", url);
            const existingModal = document.querySelector('.attachment-modal');
            if (existingModal) existingModal.remove();

            const modal = document.createElement('div');
            modal.className = 'attachment-modal';
            modal.innerHTML = `
                <div class="modal-content">
                    <img src="${url}" alt="Attachment Preview" />
                    <button class="close-modal" onclick="closeModal()">×</button>
                </div>
            `;

            document.body.appendChild(modal);

            modal.addEventListener('click', (e) => {
                if (e.target === modal) closeModal();
            });
        }

        function closeModal() {
            const modal = document.querySelector('.attachment-modal');
            if (modal) modal.remove();
        }
    </script>
    '''

    return timeline_html

# Example usage
